 1	import React, { FC } from 'react';
 2	import { Controller, useFormContext } from 'react-hook-form';
 3	
 4	import HelpTextIcon from '@kubevirt-utils/components/HelpTextIcon/HelpTextIcon';
 5	import { FEATURE_HCO_PERSISTENT_RESERVATION } from '@kubevirt-utils/hooks/useFeatures/constants';
 6	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { diskTypes } from '@kubevirt-utils/resources/vm/utils/disk/constants';
 9	import { getDiskDrive } from '@kubevirt-utils/resources/vm/utils/disk/selectors';
10	import { Checkbox, ExpandableSection, Split, Stack, StackItem } from '@patternfly/react-core';
11	
12	import { V1DiskFormState } from '../../utils/types';
13	import { LUN_RESERVATION_FIELD, SHARABLE_FIELD } from '../utils/constants';
14	import { getDiskSharable, getLunReservation } from '../utils/selectors';
15	
16	const AdvancedSettings: FC = () => {
17	  const { t } = useKubevirtTranslation();
18	  const { control, setValue, watch } = useFormContext<V1DiskFormState>();
19	  const disk = watch('disk');
20	
21	  const diskType = getDiskDrive(disk);
22	
23	  const sharable = getDiskSharable(disk);
24	  const lunReservation = getLunReservation(disk);
25	
26	  const { featureEnabled } = useFeatures(FEATURE_HCO_PERSISTENT_RESERVATION);
27	
28	  const isLunType = diskType === diskTypes.lun;
29	  return (
30	    <ExpandableSection toggleText={t('Advanced settings')}>
31	      <Stack hasGutter>
32	        <StackItem>
33	          <Split hasGutter>
34	            <Controller
35	              render={({ field: { onChange, value } }) => (
36	                <Checkbox
37	                  id="sharable-disk"
38	                  isChecked={value || isLunType}
39	                  isDisabled={lunReservation || isLunType}
40	                  label={t('Share this disk between multiple VirtualMachines')}
41	                  onChange={(_event, checked) => onChange(checked)}
42	                />
43	              )}
44	              control={control}
45	              name={SHARABLE_FIELD}
46	            />
47	            <HelpTextIcon bodyContent={t('Allows concurrent access by multiple VirtualMachines')} />
48	          </Split>
49	        </StackItem>
50	        <StackItem>
51	          <Split hasGutter>
52	            <Checkbox
53	              id="lun-reservation"
54	              isChecked={disk?.lun?.reservation}
55	              isDisabled={sharable || !isLunType || !featureEnabled}
56	              label={t('Set SCSI reservation for disk')}
57	              onChange={(_event, checked) => setValue(LUN_RESERVATION_FIELD, checked)}
58	            />
59	            <HelpTextIcon
60	              bodyContent={t(
61	                'The disk must be attached to the VirtualMAchine as a SCSI LUN for this option to work. It should only be used for cluster-aware applications',
62	              )}
63	            />
64	          </Split>
65	        </StackItem>
66	      </Stack>
67	    </ExpandableSection>
68	  );
69	};
70	
71	export default AdvancedSettings;

